import React from "react";
import { motion } from "framer-motion";
import ContentCard from '../components/body-card/card'
const Experience = () => {
  return (
    <div className="experience-page">
      <header className="Experience-header">
        <h1>My Experience</h1>
        <a
          className="resume-link"
          href="https://drive.google.com/file/d/1BSOmIJkslkfdxdRIyHQdEvIqPEM4RD9s/view?usp=share_link"
          target="_blank"
          rel="noreferrer"
        >
          My Resume
        </a>
      </header>
      <div className="exp-body">
        <div className="section1">
          <motion.div
            className="one body-item"
            initial={{ opacity: 0 }}
            whileInView={{ opacity: 1 }}
            transition={{ duration: 1 }}
            viewport={{ once: true }}
          >
            <ContentCard
              header={"Indiana University: Bloomington"}
              subtext={"2019 - 2023"}
            />
          </motion.div>
          <motion.div
            className="two body-item"
            initial={{ opacity: 0 }}
            whileInView={{ opacity: 1 }}
            transition={{ duration: 1 }}
            viewport={{ once: true }}
          >
            <ContentCard header={"Work Experience"} subtext={""} />
          </motion.div>
        </div>
        <div className="section2">
          <motion.div
            className="three body-item"
            initial={{ opacity: 0 }}
            whileInView={{ opacity: 1 }}
            transition={{ duration: 1 }}
            viewport={{ once: true }}
          >
            <ContentCard header={"Technical Skills"} subtext={""} />
          </motion.div>
        </div>
        <div className="section3">
          <motion.div
            className="four body-item"
            initial={{ opacity: 0 }}
            whileInView={{ opacity: 1 }}
            transition={{ duration: 1 }}
            viewport={{ once: true }}
          >
            <ContentCard header={"Soft Skills"} subtext={""} />
          </motion.div>
        </div>
      </div>
    </div>
  );
};

export default Experience;
